def format_timestamp(value: str | None) -> str | None:
    if value is None:
        return None
    stripped = value.strip()
    if not stripped:
        return None
    if stripped.isdigit():
        return datetime.fromtimestamp(int(stripped), tz=DISPLAY_TIMEZONE).strftime(
            "%Y-%m-%d %H:%M:%S %Z"
        )

